from __future__ import annotations

from langchain_text_splitters import RecursiveCharacterTextSplitter

from ai.app.config import settings
from ai.app.models import ChunkRecord, DocumentRecord
from ai.app.utils import make_doc_id

class DocumentChunker:
 def __init__(self) -> None:
 self.splitter = RecursiveCharacterTextSplitter(
 chunk_size=settings.chunk_size,
 chunk_overlap=settings.chunk_overlap,
 separators=["\n\n", "\n", ". ", " ", ""],
 )

 def chunk_documents(self, docs: list[DocumentRecord]) -> list[ChunkRecord]:
 chunks: list[ChunkRecord] = []

 for doc in docs:
 split_texts = self.splitter.split_text(doc.text)
 for idx, chunk_text in enumerate(split_texts):
 chunk_id = make_doc_id(doc.doc_id, str(idx))
 metadata = dict(doc.metadata)
 metadata.update(
 {
 "chunk_index": idx,
 "parent_doc_id": doc.doc_id,
 }
 )

 chunks.append(
 ChunkRecord(
 chunk_id=chunk_id,
 parent_doc_id=doc.doc_id,
 text=chunk_text,
 metadata=metadata,
 )
 )

 return chunks

from __future__ import annotations

from typing import Any

import chromadb
from chromadb.api.models.Collection import Collection
from sentence_transformers import SentenceTransformer

from ai.app.config import settings
from ai.app.models import ChunkRecord

class EmbeddingStore:
 def __init__(self) -> None:
 self.model = SentenceTransformer(settings.embedding_model_name)
 self.client = chromadb.PersistentClient(path=str(settings.chroma_dir))
 self.collection: Collection = self.client.get_or_create_collection(
 name=settings.chroma_collection_name,
 metadata={"description": "Career evidence knowledge base"},
 )

 def embed_texts(self, texts: list[str]) -> list[list[float]]:
 vectors = self.model.encode(texts, normalize_embeddings=True)
 return vectors.tolist()

 def index_chunks(self, chunks: list[ChunkRecord], batch_size: int = 64) -> None:
 for start in range(0, len(chunks), batch_size):
 batch = chunks[start : start + batch_size]
 ids = [chunk.chunk_id for chunk in batch]
 docs = [chunk.text for chunk in batch]
 metadatas = [self._normalize_metadata(chunk.metadata) for chunk in batch]
 embeddings = self.embed_texts(docs)

 self.collection.upsert(
 ids=ids,
 documents=docs,
 metadatas=metadatas,
 embeddings=embeddings,
 )

 def query(self, query_text: str, top_k: int = 5, where: dict[str, Any] | None = None) -> dict[str, Any]:
 query_embedding = self.embed_texts([query_text])[0]
 return self.collection.query(
 query_embeddings=[query_embedding],
 n_results=top_k,
 where=where,
 )

 @staticmethod
 def _normalize_metadata(metadata: dict[str, Any]) -> dict[str, Any]:
 normalized: dict[str, Any] = {}
 for key, value in metadata.items():
 if isinstance(value, (str, int, float, bool)) or value is None:
 normalized[key] = value
 else:
 normalized[key] = str(value)
 return normalized

from __future__ import annotations

import base64
from pathlib import Path
from typing import Any

import requests

from ai.app.config import settings
from ai.app.models import DocumentRecord
from ai.app.utils import clean_text, make_doc_id, redact_secrets

class GitHubIngestor:
 def __init__(self) -> None:
 self.session = requests.Session()
 headers = {
 "Accept": "application/vnd.github+json",
 "User-Agent": "career-rag-mvp",
 }
 if settings.github_token:
 headers["Authorization"] = f"Bearer {settings.github_token}"
 self.session.headers.update(headers)

 def _get(self, url: str, params: dict[str, Any] | None = None) -> Any:
 response = self.session.get(url, params=params, timeout=settings.github_timeout_seconds)
 response.raise_for_status()
 return response.json()

 def list_user_repos(self, username: str | None = None, limit: int = 5) -> list[dict[str, Any]]:
 username = username or settings.github_username
 if not username:
 raise ValueError("GitHub username not found. Set GITHUB_USERNAME in .env")

 repos = self._get(
 f"{settings.github_api_base}/users/{username}/repos",
 params={"per_page": min(limit, 100), "sort": "updated"},
 )
 return repos[:limit]

 def should_include_file(self, path_str: str, size: int = 0) -> bool:
 path = Path(path_str)

 if any(part in settings.ignored_directories for part in path.parts):
 return False

 if size > settings.max_file_size_bytes:
 return False

 lower_name = path.name.lower()
 if any(lower_name.endswith(pattern) for pattern in settings.ignored_file_patterns):
 return False

 if path.name in settings.allowed_exact_names:
 return True

 return path.suffix.lower() in settings.allowed_extensions

 def fetch_repo_tree(self, owner: str, repo: str, branch: str) -> list[dict[str, Any]]:
 tree_url = f"{settings.github_api_base}/repos/{owner}/{repo}/git/trees/{branch}"
 data = self._get(tree_url, params={"recursive": "1"})
 return data.get("tree", [])

 def fetch_file_content(self, owner: str, repo: str, file_path: str) -> str | None:
 url = f"{settings.github_api_base}/repos/{owner}/{repo}/contents/{file_path}"
 try:
 data = self._get(url)
 except requests.HTTPError:
 return None

 if isinstance(data, list):
 return None

 if data.get("encoding") == "base64" and data.get("content"):
 try:
 decoded = base64.b64decode(data["content"])
 return decoded.decode("utf-8", errors="ignore")
 except Exception:
 return None

 download_url = data.get("download_url")
 if download_url:
 try:
 response = self.session.get(download_url, timeout=settings.github_timeout_seconds)
 response.raise_for_status()
 return response.text
 except Exception:
 return None

 return None

 def ingest_repo(self, owner: str, repo: str, branch: str = "main") -> list[DocumentRecord]:
 records: list[DocumentRecord] = []

 try:
 tree = self.fetch_repo_tree(owner, repo, branch)
 except requests.HTTPError:
 if branch == "main":
 tree = self.fetch_repo_tree(owner, repo, "master")
 branch = "master"
 else:
 raise

 for item in tree:
 if item.get("type") != "blob":
 continue

 path_str = item.get("path", "")
 size = item.get("size", 0)

 if not self.should_include_file(path_str, size):
 continue

 content = self.fetch_file_content(owner, repo, path_str)
 if not content:
 continue

 cleaned = clean_text(redact_secrets(content))
 if len(cleaned) < 20:
 continue

 record = DocumentRecord(
 doc_id=make_doc_id("github", owner, repo, path_str),
 text=cleaned,
 metadata={
 "source_type": "github_repo",
 "owner": owner,
 "repo": repo,
 "branch": branch,
 "file_path": path_str,
 "file_size": size,
 "url": f"https://github.com/{owner}/{repo}/blob/{branch}/{path_str}",
 },
 )
 records.append(record)

 return records

 def ingest_selected_repos(self, repo_names: list[str], owner: str | None = None) -> list[DocumentRecord]:
 owner = owner or settings.github_username
 if not owner:
 raise ValueError("GitHub username not found. Set GITHUB_USERNAME in .env")

 all_records: list[DocumentRecord] = []
 for repo_name in repo_names:
 repo_records = self.ingest_repo(owner=owner, repo=repo_name)
 all_records.extend(repo_records)
 return all_records

from __future__ import annotations

import json
import re
from typing import Any

import cohere

from ai.app.config import settings

class CohereClient:
 def __init__(self) -> None:
 if not settings.cohere_api_key:
 raise ValueError("COHERE_API_KEY is missing in .env")

 self.client = cohere.ClientV2(api_key=settings.cohere_api_key)
 self.model_name = settings.cohere_model

 def generate_text(self, prompt: str, temperature: float = 0.2) -> str:
 response = self.client.chat(
 model=self.model_name,
 messages=[
 {
 "role": "user",
 "content": prompt,
 }
 ],
 temperature=temperature,
 )

 text = self._extract_text(response)
 return text.strip()

 def generate_json(self, prompt: str, temperature: float = 0.1) -> dict[str, Any]:
 full_prompt = (
 prompt
 + "\n\nReturn only valid JSON. Do not wrap it in markdown fences."
 )

 response = self.client.chat(
 model=self.model_name,
 messages=[
 {
 "role": "user",
 "content": full_prompt,
 }
 ],
 temperature=temperature,
 )

 text = self._extract_text(response).strip()

 try:
 return json.loads(text)
 except json.JSONDecodeError:
 text = re.sub(r"^```json\s*", "", text)
 text = re.sub(r"\s*```$", "", text)
 match = re.search(r"\{.*\}", text, flags=re.DOTALL)
 if match:
 return json.loads(match.group(0))
 raise

 @staticmethod
 def _extract_text(response: Any) -> str:
 parts: list[str] = []
 for item in getattr(response, "message", {}).content:
 if getattr(item, "type", "") == "text":
 parts.append(item.text)
 return "\n".join(parts)

from __future__ import annotations

from typing import Any

from ai.app.llm.cohere_client import CohereClient
from ai.app.models import JobRequirements, RetrievedEvidence
from ai.app.llm.prompt_builder import PromptBuilder

class ResumeGenerator:
 def __init__(self) -> None:
 self.client = CohereClient()

 def generate_structured_resume(
 self,
 job_description: str,
 requirements: JobRequirements,
 evidence: list[RetrievedEvidence],
 ) -> dict[str, Any]:
