import {
 BrowserRouter,
 Routes,
 Route,
 Link,
 useLocation,
} from "react-router-dom";
// import Messages from './pages/Messages'
import Upload from "./pages/Upload";
import Profile from "./pages/Profile/Profile";
import CVGenerator from "./pages/CVGenerator";

function Nav() {
 const { pathname } = useLocation();
 return (
 <nav className="bg-gray-900 border-b border-gray-800 px-8 py-4 flex gap-6">
 <span className="text-white font-bold mr-auto">eHacks</span>
 <Link
 to="/"
 className={`text-sm ${pathname === "/" ? "text-white" : "text-gray-400 hover:text-white"} transition`}
 >
 Profile
 </Link>
 <Link
 to="/upload"
 className={`text-sm ${pathname === "/upload" ? "text-white" : "text-gray-400 hover:text-white"} transition`}
 >
 Upload
 </Link>
 <Link className={`text-sm ${pathname === "/cv" ? "text-white" : "text-gray-400 hover:text-white"} transition`}
 to="/cv">CV Generator</Link>
 </nav>
 );
}

export default function App() {
 return (
 <BrowserRouter>
 <Nav />
 <Routes>
 <Route path="/" element={<Profile />} />
 <Route path="/upload" element={<Upload />} />
 <Route path="/cv" element={<CVGenerator />} />
 </Routes>
 </BrowserRouter>
 );
}

import { createContext, useContext, useState, useRef } from 'react'

interface Toast {
 id: number
 message: string
 type: 'success' | 'error'
}

interface ToastContextType {
 showToast: (message: string, type?: 'success' | 'error') => void
}

const ToastContext = createContext<ToastContextType>({ showToast: () => {} })

export const useToast = () => useContext(ToastContext)

export function ToastProvider({ children }: { children: React.ReactNode }) {
 const [toasts, setToasts] = useState<Toast[]>([])
 const counter = useRef(0)

 const showToast = (message: string, type: 'success' | 'error' = 'success') => {
 const id = ++counter.current
 setToasts(prev => [...prev, { id, message, type }])
 setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000)
 }

 return (
 <ToastContext.Provider value={{ showToast }}>
 {children}
 <div className="fixed bottom-6 right-6 flex flex-col gap-2 z-50">
 {toasts.map(toast => (
 <div
 key={toast.id}
 className={`px-4 py-3 rounded-xl text-sm text-white shadow-lg transition ${
 toast.type === 'error' ? 'bg-red-600' : 'bg-green-600'
 }`}
 >
 {toast.message}
 </div>
 ))}
 </div>
 </ToastContext.Provider>
 )
}

import { useState, useEffect } from "react";
import ReactQuill from "react-quill-new";
import "react-quill-new/dist/quill.snow.css";
import {
 getJDs,
 createJD,
 updateJD,
 deleteJD,
 generateCV,
} from "../services/cvGenerator";
import { useToast } from "../context/ToastContext";

interface JDEntry {
 _id: string;
 title: string;
 content: string;
 cv: string | null;
}

export default function CVGenerator() {
 const [entries, setEntries] = useState<JDEntry[]>([]);
 const [activeId, setActiveId] = useState<string | null>(null);
 const [loading, setLoading] = useState(false);
 const [saving, setSaving] = useState(false);

 // inside component
 const { showToast } = useToast();

 const active = entries.find((e) => e._id === activeId) ?? null;

 useEffect(() => {
 getJDs().then((res) => {
 const data = res.data.data;
 setEntries(data);
 if (data.length > 0) setActiveId(data[0]._id);
 });
 }, []);

 const handleNew = async () => {
 const res = await createJD(`Job Description ${entries.length + 1}`, "");
 const newEntry = res.data.data;
 setEntries((prev) => [...prev, newEntry]);
 setActiveId(newEntry._id);
 };

 const handleContentChange = (value: string) => {
 if (!active) return;
 setEntries((prev) =>
 prev.map((e) => (e._id === activeId ? { ...e, content: value } : e)),
 );
 };

 const handleTitleChange = (value: string) => {
 if (!active) return;
 setEntries((prev) =>
 prev.map((e) => (e._id === activeId ? { ...e, title: value } : e)),
 );
 };

 // update handleSave
 const handleSave = async () => {
 if (!active) return;
 setSaving(true);
 try {
 await updateJD(active._id, active.title, active.content);
 showToast("JD saved successfully");
 } catch (err) {
 showToast("Failed to save JD", "error");
 } finally {
 setSaving(false);
 }
 };

 // update handleDelete
 const handleDelete = async (_id: string) => {
 try {
 await deleteJD(_id);
 const remaining = entries.filter((e) => e._id !== _id);
 setEntries(remaining);
 if (activeId === _id) setActiveId(remaining[0]?._id ?? null);
 showToast("JD deleted");
 } catch (err) {
 showToast("Failed to delete JD", "error");
 }
 };

 // update handleGenerate
 const handleGenerate = async () => {
 if (!active) return;
 setLoading(true);
 try {
 await handleSave();
 const res = await generateCV(active._id);
 setEntries((prev) =>
 prev.map((e) => (e._id === activeId ? { ...e, cv: res.data.data } : e)),
 );
 showToast("CV generated successfully");
 } catch (err) {
 showToast("Failed to generate CV", "error");
 } finally {
 setLoading(false);
 }
 };

 return (
 <div className="min-h-screen bg-gray-950 text-white flex flex-col">
 <header className="bg-gray-900 border-b border-gray-800 px-6 py-4 flex items-center justify-between">
 <h1 className="text-lg font-semibold">CV Generator</h1>
 <span className="text-xs text-gray-500">
 {entries.length} job description{entries.length !== 1 ? "s" : ""}
 </span>
 </header>

 <div className="flex flex-1 overflow-hidden">
 <aside className="w-60 bg-gray-900 border-r border-gray-800 flex flex-col">
 <div className="p-4">
 <button
 onClick={handleNew}
 className="w-full bg-indigo-600 hover:bg-indigo-500 text-white text-sm rounded-lg py-2 transition"
 >
 + New JD
 </button>
 </div>
 <div className="flex flex-col gap-1 px-2 overflow-y-auto">
 {entries.map((entry) => (
 <div
 key={entry._id}
 onClick={() => setActiveId(entry._id)}
 className={`flex items-center justify-between px-3 py-2 rounded-lg cursor-pointer group transition ${
 activeId === entry._id
 ? "bg-gray-700 text-white"
 : "text-gray-400 hover:bg-gray-800 hover:text-white"
 }`}
 >
 <div className="flex items-center gap-2 min-w-0">
 <span
 className={`w-2 h-2 rounded-full flex-shrink-0 ${entry.cv ? "bg-green-500" : "bg-gray-600"}`}
 />
 <span className="text-sm truncate">{entry.title}</span>
 </div>
 {entries.length > 1 && (
 <button
 onClick={(e) => {
 e.stopPropagation();
 handleDelete(entry._id);
 }}
 className="text-gray-600 hover:text-red-400 text-xs opacity-0 group-hover:opacity-100 transition"
 >
 ✕
 </button>
 )}
 </div>
 ))}
 </div>
 </aside>

 {active ? (
 <main className="flex-1 flex flex-col lg:flex-row overflow-hidden">
 <div className="flex-1 flex flex-col p-6 border-r border-gray-800 overflow-y-auto">
 <div className="flex items-center justify-between mb-3">
 <input
 value={active.title}
 onChange={(e) => handleTitleChange(e.target.value)}
 className="bg-transparent text-sm font-medium text-gray-300 focus:outline-none border-b border-transparent focus:border-gray-600 pb-0.5 transition"
 />
 <div className="flex gap-2">
 <button
 onClick={handleSave}
 disabled={saving}
 className="border border-gray-700 hover:border-gray-500 text-gray-300 text-sm rounded-lg px-4 py-2 transition disabled:opacity-40"
 >
 {saving ? "Saving..." : "Save"}
 </button>
 <button
 onClick={handleGenerate}
 disabled={loading || !active.content}
 className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-40 disabled:cursor-not-allowed text-white text-sm rounded-lg px-4 py-2 transition"
 >
 {loading ? "Generating..." : "Generate CV →"}
 </button>
 </div>
 </div>
 <ReactQuill
 theme="snow"
 value={active.content}
 onChange={handleContentChange}
 placeholder="Paste or type the job description here..."
 className="flex-1 bg-gray-800 rounded-xl text-white"
 />
 </div>

 <div className="flex-1 flex flex-col p-6 overflow-y-auto">
 <div className="flex items-center justify-between mb-4">
 <h2 className="text-sm font-medium text-gray-300">
 Generated CV
 </h2>
 {active.cv && (
 <button
 onClick={() => navigator.clipboard.writeText(active.cv!)}
 className="text-xs text-indigo-400 hover:text-indigo-300 transition"
 >
 Copy
 </button>
 )}
 </div>
 {active.cv ? (
 <div
 className="bg-gray-900 rounded-xl p-6 text-sm text-gray-200 leading-relaxed whitespace-pre-wrap flex-1"
 dangerouslySetInnerHTML={{ __html: active.cv }}
 />
 ) : (
 <div className="flex-1 flex flex-col items-center justify-center text-center text-gray-600">
 <span className="text-4xl mb-3">📄</span>
 <p className="text-sm">Your generated CV will appear here</p>
 <p className="text-xs mt-1">
 Paste a job description and hit Generate
 </p>
 </div>
 )}
 </div>
 </main>
 ) : (
 <div className="flex-1 flex items-center justify-center text-gray-600">
 <p className="text-sm">Click + New JD to get started</p>
 </div>
 )}
 </div>
 </div>
 );
}

import { useState, useEffect } from 'react'
import { getMessages, postMessage } from '../services/messages'

interface Message {
 id: number
 text: string
 author: string
}

export default function Messages() {
 const [messages, setMessages] = useState<Message[]>([])
 const [text, setText] = useState('')
 const [author, setAuthor] = useState('')

 useEffect(() => {
 getMessages().then(res => setMessages(res.data.data))
 }, [])

 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault()
 const res = await postMessage(text, author)
 setMessages(prev => [...prev, res.data.data])
 setText('')
 }

 return (
 <div>
 {messages.map(msg => (
 <p key={msg.id}><b>{msg.author}:</b> {msg.text}</p>
 ))}
 <form onSubmit={handleSubmit}>
 <input value={author} onChange={e => setAuthor(e.target.value)} placeholder="Name" />
 <input value={text} onChange={e => setText(e.target.value)} placeholder="Message" />
 <button type="submit">Send</button>
 </form>
 </div>
 )
}

import { useState, useEffect } from 'react'
import { getEducation, createEducation, updateEducation, deleteEducation } from '../../services/education'
import { useToast } from '../../context/ToastContext'

interface Education {
 _id: string
 institution: string
 degree: string
 field: string
 startDate: string
 endDate: string
 current: boolean
 source: string
}

const empty = {
 institution: '', degree: '', field: '',
 startDate: '', endDate: '', current: false
}

export default function EducationSection() {
 const { showToast } = useToast()
 const [education, setEducation] = useState<Education[]>([])
 const [adding, setAdding] = useState(false)
 const [editingId, setEditingId] = useState<string | null>(null)
 const [form, setForm] = useState(empty)

 useEffect(() => {
 getEducation().then(res => setEducation(res.data.data))
 }, [])

 const resetForm = () => { setForm(empty); setAdding(false); setEditingId(null) }

 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault()
 try {
 if (editingId) {
 const res = await updateEducation(editingId, form)
 setEducation(prev => prev.map(e => e._id === editingId ? res.data.data : e))
 showToast('Education updated')
 } else {
 const res = await createEducation(form)
 setEducation(prev => [res.data.data, ...prev])
 showToast('Education added')
 }
 resetForm()
 } catch {
 showToast('Failed to save education', 'error')
 }
 }

 const handleEdit = (edu: Education) => {
 setEditingId(edu._id)
 setForm({ institution: edu.institution, degree: edu.degree, field: edu.field, startDate: edu.startDate, endDate: edu.endDate, current: edu.current })
 setAdding(true)
 }

 const handleDelete = async (_id: string) => {
 try {
 await deleteEducation(_id)
 setEducation(prev => prev.filter(e => e._id !== _id))
 showToast('Education deleted')
 } catch {
 showToast('Failed to delete', 'error')
 }
 }

 return (
 <div className="bg-gray-900 rounded-2xl p-6">
 <div className="flex items-center justify-between mb-6">
 <div>
 <h2 className="text-xl font-semibold">Education</h2>
 <p className="text-xs text-gray-500 mt-1">Your academic background</p>
 </div>
 {!adding && (
 <button onClick={() => setAdding(true)} className="text-sm text-indigo-400 hover:text-indigo-300 transition">
 + Add
 </button>
 )}
 </div>

 {/* Form */}
 {adding && (
 <form onSubmit={handleSubmit} className="flex flex-col gap-4 mb-6 pb-6 border-b border-gray-800">
 <div className="grid grid-cols-2 gap-4">
 <div className="col-span-2 flex flex-col gap-1">
 <label className="text-xs text-gray-500">Institution</label>
 <input
 value={form.institution}
 onChange={e => setForm(prev => ({ ...prev, institution: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Degree</label>
 <input
 value={form.degree}
 onChange={e => setForm(prev => ({ ...prev, degree: e.target.value }))}
 placeholder="e.g. Bachelor of Science"
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Field of Study</label>
 <input
 value={form.field}
 onChange={e => setForm(prev => ({ ...prev, field: e.target.value }))}
 placeholder="e.g. Computer Science"
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Start Date</label>
 <input
 type="month"
 value={form.startDate}
 onChange={e => setForm(prev => ({ ...prev, startDate: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">End Date</label>
 <input
 type="month"
 value={form.endDate}
 disabled={form.current}
 onChange={e => setForm(prev => ({ ...prev, endDate: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500 disabled:opacity-40"
 />
 </div>
 <div className="col-span-2 flex items-center gap-2">
 <input
 type="checkbox"
 id="current"
 checked={form.current}
 onChange={e => setForm(prev => ({ ...prev, current: e.target.checked, endDate: '' }))}
 className="accent-indigo-500"
 />
 <label htmlFor="current" className="text-xs text-gray-400">I currently study here</label>
 </div>
 </div>
 <div className="flex gap-3">
 <button type="submit" className="bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg px-4 py-2 text-sm transition">
 {editingId ? 'Update' : 'Add'}
 </button>
 <button type="button" onClick={resetForm} className="text-sm text-gray-400 hover:text-white transition">
 Cancel
 </button>
 </div>
 </form>
 )}

 {/* List */}
 {education.length === 0 && !adding && (
 <p className="text-sm text-gray-600">No education added yet</p>
 )}
 <div className="flex flex-col gap-4">
 {education.map(edu => (
 <div key={edu._id} className="flex items-start justify-between gap-4 pb-4 border-b border-gray-800 last:border-0">
 <div className="flex-1 min-w-0">
 <div className="flex items-center gap-2">
 <p className="text-sm font-medium text-white">{edu.institution}</p>
 {edu.source === 'linkedin' && (
 <span className="text-xs bg-blue-900 text-blue-400 px-2 py-0.5 rounded-full">LinkedIn</span>
 )}
 </div>
 <p className="text-xs text-gray-400 mt-0.5">{edu.degree} {edu.field && `· ${edu.field}`}</p>
 <p className="text-xs text-gray-600 mt-0.5">
 {edu.startDate} — {edu.current ? 'Present' : edu.endDate}
 </p>
 </div>
 <div className="flex gap-3 flex-shrink-0">
 <button onClick={() => handleEdit(edu)} className="text-xs text-gray-400 hover:text-white transition">Edit</button>
 <button onClick={() => handleDelete(edu._id)} className="text-xs text-gray-400 hover:text-red-400 transition">Delete</button>
 </div>
 </div>
 ))}
 </div>
 </div>
 )
}

import { useState, useEffect, useRef } from 'react'
import { autofillFromLinkedin, getProfile, updateProfile, uploadLinkedinPdf } from '../../services/user'
import { useToast } from '../../context/ToastContext'
import { getFileUrl } from '../../utils/url'

interface Profile {
 firstName: string
 lastName: string
 email: string
 phone: string
 bio: string
 location: string
 githubUsername: string
 skills: string[]
 linkedinPdf: string | null
}

const FIELDS = [
 { key: 'firstName', label: 'First Name' },
 { key: 'lastName', label: 'Last Name' },
 { key: 'email', label: 'Email' },
 { key: 'phone', label: 'Phone' },
 { key: 'location', label: 'Location' },
 { key: 'githubUsername', label: 'GitHub Username' },
] as const

const empty: Profile = {
 firstName: '', lastName: '', email: '',
 phone: '', bio: '', location: '',
 githubUsername: '', skills: [], linkedinPdf: null
}

export default function Profile() {
 const { showToast } = useToast()
 const [editing, setEditing] = useState(false)
 const [profile, setProfile] = useState<Profile>(empty)
 const [form, setForm] = useState<Profile>(empty)
 const [loading, setLoading] = useState(false)
 const [skillInput, setSkillInput] = useState('')
 const [uploading, setUploading] = useState(false)
 const fileRef = useRef<HTMLInputElement>(null)

 useEffect(() => {
 getProfile().then(res => {
 setProfile(res.data.data)
 setForm(res.data.data)
 })
 }, [])

 const handleSave = async (e: React.FormEvent) => {
 e.preventDefault()
 setLoading(true)
 try {
 const res = await updateProfile(form)
 setProfile(res.data.data)
 setEditing(false)
 showToast('Profile saved successfully')
 } catch {
 showToast('Failed to save profile', 'error')
 } finally {
 setLoading(false)
 }
 }

 const handleAddSkill = (e: React.KeyboardEvent) => {
 if (e.key !== 'Enter') return
 e.preventDefault()
 const skill = skillInput.trim()
 if (!skill || form.skills.includes(skill)) return
 setForm(prev => ({ ...prev, skills: [...prev.skills, skill] }))
 setSkillInput('')
 }

 const handleRemoveSkill = (skill: string) => {
 setForm(prev => ({ ...prev, skills: prev.skills.filter(s => s !== skill) }))
 }

 const handleLinkedinUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
 if (!e.target.files?.[0]) return
 setUploading(true)
 try {
 const res = await uploadLinkedinPdf(e.target.files[0])
 setProfile(res.data.data)
 setForm(res.data.data)
 showToast('LinkedIn PDF uploaded — auto-fill coming soon')
 } catch {
 showToast('Failed to upload LinkedIn PDF', 'error')
 } finally {
 setUploading(false)
 }
 }

const [autofilling, setAutofilling] = useState(false)

const handleRemoveLinkedin = async () => {
 try {
 await updateProfile({ ...profile, linkedinPdf: null })
 setProfile(prev => ({ ...prev, linkedinPdf: null }))
 setForm(prev => ({ ...prev, linkedinPdf: null }))
 showToast('LinkedIn PDF removed')
 } catch {
 showToast('Failed to remove', 'error')
 }
}

const handleAutoFill = async () => {
 setAutofilling(true)
 try {
 const res = await autofillFromLinkedin()
 const { user, workExperience, education } = res.data.data
 setProfile(user)
 setForm(user)
 showToast(`Auto-filled profile with ${workExperience.length} jobs and ${education.length} education entries`)
 } catch {
 showToast('Auto-fill failed', 'error')
 } finally {
 setAutofilling(false)
 }
}

 return (
 <div className="min-h-screen bg-gray-950 text-white p-8">
 <div className="max-w-2xl mx-auto flex flex-col gap-6">

 {/* LinkedIn Import */}
<div className="bg-gray-900 rounded-2xl p-6">
 <div className="flex items-center justify-between mb-4">
 <div>
 <h3 className="text-sm font-medium text-white">Import from LinkedIn</h3>
 <p className="text-xs text-gray-500 mt-0.5">Upload your LinkedIn PDF to auto-fill profile</p>
 </div>
 {profile.linkedinPdf && (
 <span className="text-xs bg-green-900 text-green-400 px-2 py-1 rounded-md">Uploaded</span>
 )}
 </div>

 {/* uploaded file info */}
 {profile.linkedinPdf && (
 <div className="flex items-center justify-between bg-gray-800 rounded-xl px-4 py-3 mb-4">
 <div className="flex items-center gap-3">
 <span>📄</span>
 <div>
 <p className="text-sm text-white">{profile.linkedinPdf}</p>
 <p className="text-xs text-gray-500 mt-0.5">LinkedIn PDF</p>
 </div>
 </div>
 <div className="flex items-center gap-3">
 <a
 href={getFileUrl(profile.linkedinPdf)}
 target="_blank"
 rel="noreferrer"
 className="text-xs text-indigo-400 hover:text-indigo-300 transition"
 >
 View
 </a>
 <button
 onClick={handleRemoveLinkedin}
 className="text-xs text-gray-500 hover:text-red-400 transition"
 >
 Remove
 </button>
 </div>
 </div>
 )}

 <div className="flex items-center gap-3">
 <button
 onClick={() => fileRef.current?.click()}
 disabled={uploading}
 className="bg-blue-600 hover:bg-blue-500 disabled:opacity-40 text-white text-sm rounded-lg px-4 py-2 transition"
 >
 {uploading ? 'Uploading...' : profile.linkedinPdf ? '↺ Re-upload' : '📎 Upload LinkedIn PDF'}
 </button>
 {profile.linkedinPdf && (
 <button
 onClick={handleAutoFill}
 disabled={autofilling}
 className="border border-indigo-500 hover:bg-indigo-500 disabled:opacity-40 text-indigo-400 hover:text-white text-sm rounded-lg px-4 py-2 transition"
 >
 {autofilling ? 'Auto-filling...' : '✨ Auto-fill from PDF'}
 </button>
 )}
 <input
 ref={fileRef}
 type="file"
 accept=".pdf"
 onChange={handleLinkedinUpload}
 className="hidden"
 />
 </div>
</div>

 {/* Profile */}
 <div className="bg-gray-900 rounded-2xl p-6">
 <div className="flex items-center justify-between mb-6">
 <div>
 <h2 className="text-xl font-semibold">Profile</h2>
 <p className="text-xs text-gray-500 mt-1">Your details used for CV and portfolio generation</p>
 </div>
 {!editing && (
 <button
 onClick={() => setEditing(true)}
 className="text-sm text-indigo-400 hover:text-indigo-300 transition"
 >
 Edit
 </button>
 )}
 </div>

 {editing ? (
 <form onSubmit={handleSave} className="flex flex-col gap-4">
 <div className="grid grid-cols-2 gap-4">
 {FIELDS.map(({ key, label }) => (
 <div key={key} className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">{label}</label>
 <input
 value={form[key] as string}
 onChange={e => setForm(prev => ({ ...prev, [key]: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 ))}

 {/* Bio */}
 <div className="col-span-2 flex flex-col gap-1">
 <label className="text-xs text-gray-500">Bio</label>
 <textarea
 value={form.bio}
 onChange={e => setForm(prev => ({ ...prev, bio: e.target.value }))}
 rows={3}
 className="bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-sm text-white focus:outline-none focus:border-indigo-500 resize-none"
 />
 </div>

 {/* Skills */}
 <div className="col-span-2 flex flex-col gap-2">
 <label className="text-xs text-gray-500">Skills — press Enter to add</label>
 <input
 value={skillInput}
 onChange={e => setSkillInput(e.target.value)}
 onKeyDown={handleAddSkill}
 placeholder="e.g. React"
 className="bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 <div className="flex flex-wrap gap-2 mt-1">
 {form.skills.map(skill => (
 <span key={skill} className="flex items-center gap-1 bg-gray-800 text-gray-300 text-xs px-3 py-1 rounded-full">
 {skill}
 <button type="button" onClick={() => handleRemoveSkill(skill)} className="text-gray-500 hover:text-red-400 transition">✕</button>
 </span>
 ))}
 </div>
 </div>
 </div>

 <div className="flex gap-3 mt-2">
 <button
 type="submit"
 disabled={loading}
 className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-40 text-white rounded-lg px-4 py-2 text-sm transition"
 >
 {loading ? 'Saving...' : 'Save'}
